class FakeSession:
    def __init__(
        self,
        *,
        run: Run | None = None,
        suite: Suite | None = None,
        connection: Connection | None = None,
        checks: tuple[Check, ...] = (),
    ) -> None:
        self._objs: dict[type, Any] = {Run: run, Suite: suite, Connection: connection}
        self._checks = list(checks)
        self.added: list[Any] = []
        self.commits = 0
        self.rollbacks = 0
        self.closed = False

    def get(self, model: type, pk: Any) -> Any:
        return self._objs.get(model)

    def scalars(self, _stmt: Any) -> Any:
        return iter(self._checks)

    def add_all(self, rows: list[Any]) -> None:
        self.added.extend(rows)

    def commit(self) -> None:
        self.commits += 1

    def rollback(self) -> None:
        self.rollbacks += 1
        self.added.clear()

    def refresh(self, obj: object) -> None:  # no-op reload (status unchanged here)
        pass

    def close(self) -> None:
        self.closed = True


